import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from 'jsr:@supabase/supabase-js@2';

// Import our modules
import { MultiSourceAggregator } from './multi-source-aggregator.ts';
import { AIEnrichmentService } from './ai-enrichment.ts';
import { TaxonomyEnhanced } from './taxonomy-enhanced.ts';
import { ScoringEngineV2 } from './scoring-engine-v2.ts';
import { extractOccupations, extractGeography } from './cv-utils.ts';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'POST, OPTIONS',
  'Access-Control-Allow-Headers': 'authorization, content-type, x-client-info, apikey',
};

function getSupabaseClient() {
  const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
  const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
  return createClient(supabaseUrl, supabaseServiceKey);
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const { userId, selectedAnalysisId, customParams } = await req.json();
    if (!userId || !selectedAnalysisId) {
      return new Response(JSON.stringify({ error: 'Missing userId or selectedAnalysisId' }), {
        status: 400,
        headers: corsHeaders
      });
    }

    const supabase = getSupabaseClient();
    console.log(`[Match-Jobs-V2] Starting for user ${userId}, analysis ${selectedAnalysisId}`);

    // ============================================================================
    // STEG 1: Hämta CV-analys
    // ============================================================================
    const { data: analysisData, error: analysisError } = await supabase
      .from('cv_analysis_jobs')
      .select('result, display_name, created_at, cv_id')
      .eq('id', selectedAnalysisId)
      .eq('user_id', userId)
      .single();

    if (analysisError || !analysisData) {
      return new Response(JSON.stringify({ error: 'CV analysis not found' }), {
        status: 404,
        headers: corsHeaders
      });
    }

    const cvData = analysisData.result;
    const cvOccupations = extractOccupations(cvData);
    const cvLocations = extractGeography(cvData);

    console.log(`[Match-Jobs-V2] Extracted ${cvOccupations.length} occupations, ${cvLocations.length} locations`);

    // ============================================================================
    // STEG 2: Taxonomy Enrichment (Enhanced)
    // ============================================================================
    const taxonomyService = new TaxonomyEnhanced(supabase);
    let taxonomyData = null;
    let relatedOccupations: string[] = [];

    if (cvOccupations[0]) {
      console.log(`[Match-Jobs-V2] Enriching occupation: ${cvOccupations[0]}`);
      taxonomyData = await taxonomyService.enrichOccupation(cvOccupations[0]);

      // Hämta relaterade yrken för bredare sökning
      relatedOccupations = await taxonomyService.getRelatedOccupations(cvOccupations[0]);
      console.log(`[Match-Jobs-V2] Found ${relatedOccupations.length} related occupations`);
    }

    // ============================================================================
    // STEG 3: Multi-Source Job Aggregation
    // ============================================================================
    const aggregator = new MultiSourceAggregator();

    console.log('[Match-Jobs-V2] Aggregating jobs from multiple sources...');
    const allJobs = await aggregator.aggregateJobs({
      primaryOccupation: cvOccupations[0] || '',
      taxonomyData,
      relatedOccupations,
      cvEducations: cvData.structuredCV?.education || [],
      userLocation: cvLocations[0] || '',
      customQuery: customParams?.q,
      maxJobsPerQuery: 1000, // 10 pages × 100
      maxTotalJobs: 2000
    });

    console.log(`[Match-Jobs-V2] Aggregated ${allJobs.length} total jobs from all sources`);

    if (allJobs.length === 0) {
      console.error('[Match-Jobs-V2] No jobs found!');
      return new Response(JSON.stringify({
        success: true,
        jobs: [],
        selectedAnalysis: {
          ...cvData,
          id: selectedAnalysisId,
          displayName: analysisData.display_name,
          createdAt: analysisData.created_at,
          cvId: analysisData.cv_id
        },
        searchTerms: { occupations: cvOccupations, locations: cvLocations },
        totalResults: 0,
        version: 'v2'
      }), {
        status: 200,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }

    // ============================================================================
    // STEG 4: AI-Powered Enrichment (CONDITIONAL - ENDAST FÖR KOMPETENSER)
    // ============================================================================
    // NYTT: Skippa AI enrichment för occupations - JobAd Links har redan strukturerad occupation data
    // AI enrichment behövs endast för kompetenser/färdigheter
    const enrichmentService = new AIEnrichmentService(supabase);

    console.log(`[Match-Jobs-V2] Enriching ${allJobs.length} jobs with AI (skills/competencies only)...`);

    // OPTIMERING: Filtrera jobb som redan har occupation_field från JobAd Links
    // Dessa behöver INGEN AI enrichment för occupations
    const jobsNeedingEnrichment = allJobs.filter(job => {
      // Om jobbet redan har occupation_field från JobAd Links, skippa occupation enrichment
      const hasOccupationData = job.occupation_field?.concept_id || job.occupation?.concept_id;
      if (hasOccupationData) {
        console.log(`[Match-Jobs-V2] Job ${job.id} already has occupation data from JobAd Links - skipping AI occupation enrichment`);
      }
      // Vi enrichar ALLA jobb för kompetenser, men detta går snabbt
      return true; // För nu enrichar vi alla för kompetenser
    });

    const enrichedJobsMap = await enrichmentService.enrichJobsBatch(
      jobsNeedingEnrichment.map(job => ({
        id: job.id,
        headline: job.headline,
        text: job.description?.text || ''
      }))
    );

    console.log(`[Match-Jobs-V2] Successfully enriched ${enrichedJobsMap.size} jobs`);

    // ============================================================================
    // STEG 5: Advanced Scoring V2
    // ============================================================================
    const scoringEngine = new ScoringEngineV2();

    console.log('[Match-Jobs-V2] Scoring jobs with enhanced algorithm...');
    const jobsWithScores = allJobs.map(job => {
      const enrichedJob = enrichedJobsMap.get(job.id) || null;

      const scoringResult = scoringEngine.calculateScore({
        cvData,
        cvOccupations,
        cvLocations,
        taxonomyData,
        job,
        enrichedJob
      });

      return {
        ...job,
        relevance: scoringResult.total,
        scoringBreakdown: scoringResult.breakdown,
        scoringExplanation: scoringResult.explanation,
        enriched: enrichedJob !== null,
        distance: scoringResult.distance
      };
    });

    // ============================================================================
    // STEG 6: Intelligent Filtering
    // ============================================================================
    console.log('[Match-Jobs-V2] Applying intelligent filters...');
    const filteredJobs = jobsWithScores.filter(job => {
      // Minimum relevans: 30 poäng
      if (job.relevance < 30) return false;

      // Kräv antingen SSYK-match ELLER kompetens-match
      const enrichedJob = enrichedJobsMap.get(job.id);
      if (!enrichedJob) return job.relevance >= 50; // Högre krav om inte enriched

      const hasSSYKMatch = enrichedJob.occupations?.some(
        occ => occ.ssyk_code === taxonomyData?.ssykCode
      );
      const hasCompetencyMatch = (enrichedJob.skills?.length || 0) >= 2;

      return hasSSYKMatch || hasCompetencyMatch || job.relevance >= 60;
    });

    console.log(`[Match-Jobs-V2] Filtered to ${filteredJobs.length} relevant jobs`);

    // ============================================================================
    // STEG 7: Sortera och begränsa
    // ============================================================================
    filteredJobs.sort((a, b) => (b.relevance || 0) - (a.relevance || 0));
    const finalJobs = filteredJobs.slice(0, 500); // Top 500

    console.log(`[Match-Jobs-V2] Returning top ${finalJobs.length} jobs`);
    console.log(`[Match-Jobs-V2] Score range: ${finalJobs[0]?.relevance || 0} - ${finalJobs[finalJobs.length - 1]?.relevance || 0}`);

    // ============================================================================
    // RETURN RESPONSE
    // ============================================================================
    return new Response(
      JSON.stringify({
        success: true,
        jobs: finalJobs,
        selectedAnalysis: {
          ...cvData,
          id: selectedAnalysisId,
          displayName: analysisData.display_name,
          createdAt: analysisData.created_at,
          cvId: analysisData.cv_id
        },
        searchTerms: { occupations: cvOccupations, locations: cvLocations },
        totalResults: finalJobs.length,
        stats: {
          totalAggregated: allJobs.length,
          enriched: enrichedJobsMap.size,
          afterFiltering: filteredJobs.length,
          returned: finalJobs.length
        },
        version: 'v2',
        improvements: [
          'Multi-source aggregation (JobAd Links, JobSearch, JobStream)',
          'AI-powered enrichment via JobAd Enrichments API',
          'Enhanced taxonomy with related occupations',
          'Improved scoring algorithm (6 factors)',
          'Intelligent filtering based on AI-extracted competencies'
        ]
      }),
      { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );

  } catch (error) {
    console.error('[Match-Jobs-V2] Error:', error);
    return new Response(
      JSON.stringify({ error: error instanceof Error ? error.message : 'Unknown error' }),
      { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  }
});

/**
 * AI-Powered Job Enrichment Service
 *
 * Använder Arbetsförmedlingens JobAd Enrichments API för att extrahera:
 * - Kompetenser (skills) med AI-precision
 * - SSYK-koder
 * - Erfarenhetskrav
 * - Utbildningsnivå
 * - Mjuka färdigheter
 *
 * API Docs: https://jobad-enrichments.api.jobtechdev.se
 */

export interface EnrichedJobData {
  jobId: string;
  occupations?: Array<{
    term: string;
    weight: number;
    ssyk_code?: string;
  }>;
  skills?: Array<{
    term: string;
    weight: number;
    type?: 'hard' | 'soft';
  }>;
  competencies?: Array<{
    term: string;
    weight: number;
    category?: string;
  }>;
  experience_required?: {
    years?: number;
    level?: string;
    weight: number;
  };
  education_level?: {
    level: string;
    field?: string;
    weight: number;
  };
  languages?: Array<{
    term: string;
    weight: number;
    level?: string;
  }>;
}

interface JobInput {
  id: string;
  headline: string;
  text: string;
}

const ENRICHMENTS_API = 'https://jobad-enrichments-api.jobtechdev.se';
const TAXONOMY_API = 'https://taxonomy.api.jobtechdev.se/v1/taxonomy';

export class AIEnrichmentService {
  private supabase: any;
  private ssykCache = new Map<string, string | null>(); // Cache för SSYK-lookups

  constructor(supabase: any) {
    this.supabase = supabase;
  }

  /**
   * Berika flera jobb samtidigt (batch processing)
   */
  async enrichJobsBatch(jobs: JobInput[]): Promise<Map<string, EnrichedJobData>> {
    console.log(`[AI Enrichment] Processing ${jobs.length} jobs...`);

    const results = new Map<string, EnrichedJobData>();

    // Steg 1: Kolla cache först
    const jobIds = jobs.map(j => j.id);
    const cached = await this.getCachedEnrichments(jobIds);

    console.log(`[AI Enrichment] Cache hit: ${cached.size}/${jobs.length} jobs`);

    // Steg 2: Identifiera jobb som behöver berikas
    const uncachedJobs = jobs.filter(job => !cached.has(job.id));

    if (uncachedJobs.length === 0) {
      console.log('[AI Enrichment] All jobs found in cache!');
      return cached;
    }

    console.log(`[AI Enrichment] Need to enrich ${uncachedJobs.length} jobs`);

    // Steg 3: Berika i batches om 100 (API-limit)
    const BATCH_SIZE = 100;
    const newEnrichments = new Map<string, EnrichedJobData>();

    for (let i = 0; i < uncachedJobs.length; i += BATCH_SIZE) {
      const batch = uncachedJobs.slice(i, i + BATCH_SIZE);
      console.log(`[AI Enrichment] Processing batch ${Math.floor(i / BATCH_SIZE) + 1}/${Math.ceil(uncachedJobs.length / BATCH_SIZE)}`);

      try {
        // Försök med API först
        const batchEnrichments = await this.enrichBatchViaAPI(batch);

        // Om API failar, använd fallback
        if (batchEnrichments.size === 0) {
          console.warn('[AI Enrichment] API failed, using local fallback');
          const fallbackEnrichments = await this.enrichBatchLocally(batch);
          fallbackEnrichments.forEach((data, id) => newEnrichments.set(id, data));
        } else {
          batchEnrichments.forEach((data, id) => newEnrichments.set(id, data));
        }

      } catch (error) {
        console.error('[AI Enrichment] Batch error:', error);
        // Fallback till lokal enrichment
        const fallbackEnrichments = await this.enrichBatchLocally(batch);
        fallbackEnrichments.forEach((data, id) => newEnrichments.set(id, data));
      }

      // Rate limiting mellan batches
      if (i + BATCH_SIZE < uncachedJobs.length) {
        await new Promise(resolve => setTimeout(resolve, 200));
      }
    }

    // Steg 4: Spara nya enrichments till cache
    if (newEnrichments.size > 0) {
      await this.saveEnrichmentsToCache(newEnrichments);
    }

    // Steg 5: Kombinera cached + nya
    const combined = new Map([...cached, ...newEnrichments]);
    console.log(`[AI Enrichment] ✅ Total enriched: ${combined.size} jobs`);

    return combined;
  }

  /**
   * Berika batch via JobAd Enrichments API
   */
  private async enrichBatchViaAPI(batch: JobInput[]): Promise<Map<string, EnrichedJobData>> {
    const results = new Map<string, EnrichedJobData>();

    try {
      // Korrekt format enligt API-dokumentation: https://jobad-enrichments-api.jobtechdev.se/
      const documents_input = batch.map(job => ({
        doc_id: job.id,
        doc_headline: job.headline,
        doc_text: job.text
      }));

      // Använder /enrichtextdocuments istället för /binary för att få:
      // - ALLA terms med confidence scores (0.0-1.0)
      // - Mer flexibel filtrering (vi bestämmer threshold)
      // - Bättre för SSYK-lookup (även låg-confidence terms)
      const response = await fetch(`${ENRICHMENTS_API}/enrichtextdocuments`, {
        method: 'POST',
        headers: {
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ documents_input })
      });

      if (!response.ok) {
        console.warn(`[AI Enrichment] API returned ${response.status}`);
        return results;
      }

      const data = await response.json();

      // API returnerar array av enriched documents direkt
      if (Array.isArray(data)) {
        for (const enrichedDoc of data) {
          const jobId = enrichedDoc.doc_id;
          const enrichedData = await this.parseAPIResponse(jobId, enrichedDoc);
          results.set(jobId, enrichedData);
        }
      }

      console.log(`[AI Enrichment] API enriched ${results.size}/${batch.length} jobs (with SSYK codes from Taxonomy API)`);

    } catch (error) {
      console.error('[AI Enrichment] API error:', error);
    }

    return results;
  }

  /**
   * Slå upp SSYK-kod för ett yrke via Taxonomy API
   */
  private async lookupSSYKCode(occupationTerm: string): Promise<string | null> {
    // Kolla cache först
    if (this.ssykCache.has(occupationTerm.toLowerCase())) {
      return this.ssykCache.get(occupationTerm.toLowerCase()) || null;
    }

    try {
      const url = `${TAXONOMY_API}/specific/concepts/ssyk?preferred-label=${encodeURIComponent(occupationTerm)}&limit=1`;

      const response = await fetch(url, {
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        console.warn(`[AI Enrichment] Taxonomy API error for "${occupationTerm}": ${response.status}`);
        this.ssykCache.set(occupationTerm.toLowerCase(), null);
        return null;
      }

      const data = await response.json();

      // API returnerar array med concepts
      if (Array.isArray(data) && data.length > 0) {
        const concept = data[0];
        const ssykCode = concept.ssyk_code_2012 || null;

        if (ssykCode) {
          console.log(`[AI Enrichment] ✅ Mapped "${occupationTerm}" → SSYK ${ssykCode}`);
          this.ssykCache.set(occupationTerm.toLowerCase(), ssykCode);
          return ssykCode;
        }
      }

      // Inget resultat
      console.warn(`[AI Enrichment] ⚠️ No SSYK code found for "${occupationTerm}"`);
      this.ssykCache.set(occupationTerm.toLowerCase(), null);
      return null;

    } catch (error) {
      console.error(`[AI Enrichment] Error looking up SSYK for "${occupationTerm}":`, error);
      this.ssykCache.set(occupationTerm.toLowerCase(), null);
      return null;
    }
  }

  /**
   * Parsa API-svar till vårt format
   * API-format från /enrichtextdocuments (UPPDATERAD - inte längre binary):
   * {
   *   doc_id: "...",
   *   doc_headline: "...",
   *   enriched_candidates: {
   *     occupations: [{ concept_label, term, term_misspelled, prediction, ... }],
   *     competencies: [{ concept_label, term, prediction, ... }],
   *     traits: [{ concept_label, term, prediction, ... }],
   *     geos: [{ concept_label, term, prediction, ... }]
   *   }
   * }
   *
   * VIKTIGT: prediction är 0.0-1.0 (AI confidence score)
   */
  private async parseAPIResponse(jobId: string, apiData: any): Promise<EnrichedJobData> {
    const enrichedCandidates = apiData.enriched_candidates || {};

    // Occupations - slå upp SSYK-kod för varje yrke via Taxonomy API
    const occupationsList = enrichedCandidates.occupations || [];

    // OPTIMERING: Gör ALLA SSYK-lookups parallellt istället för sekventiellt
    const ssykPromises = occupationsList.map((occ: any) => this.lookupSSYKCode(occ.term));
    const ssykCodes = await Promise.all(ssykPromises);

    const occupations = occupationsList.map((occ: any, index: number) => ({
      term: occ.term,
      weight: occ.prediction || 0.5, // Använd AI confidence från /enrichtextdocuments (0.0-1.0)
      ssyk_code: ssykCodes[index] // Nu hämtar vi RÄTT SSYK-kod från Taxonomy API
    }));

    // Competencies (kompetenser/färdigheter)
    const competencies = (enrichedCandidates.competencies || []).map((comp: any) => ({
      term: comp.term,
      weight: comp.prediction || 0.5, // Använd AI confidence
      category: comp.concept_label
    }));

    // Skills = både competencies och traits (mjuka färdigheter)
    const skills = [
      ...competencies.map((c: any) => ({ term: c.term, weight: c.weight, type: 'hard' as const })),
      ...(enrichedCandidates.traits || []).map((trait: any) => ({
        term: trait.term,
        weight: trait.prediction || 0.5, // Använd AI confidence
        type: 'soft' as const
      }))
    ];

    // Geos - platser (kan användas för geografisk matchning)
    const geos = (enrichedCandidates.geos || []).map((geo: any) => ({
      term: geo.term,
      weight: geo.prediction || 0.5 // Använd AI confidence
    }));

    return {
      jobId,
      occupations,
      skills,
      competencies,
      experience_required: undefined, // API ger inte detta direkt
      education_level: undefined, // API ger inte detta direkt
      languages: [] // API ger inte detta direkt
    };
  }

  /**
   * Fallback: Lokal text-baserad enrichment
   */
  private async enrichBatchLocally(batch: JobInput[]): Promise<Map<string, EnrichedJobData>> {
    const results = new Map<string, EnrichedJobData>();

    for (const job of batch) {
      const enriched = await this.enrichJobLocally(job);
      results.set(job.id, enriched);
    }

    return results;
  }

  /**
   * Lokal enrichment (enkel keyword-matching)
   */
  private async enrichJobLocally(job: JobInput): Promise<EnrichedJobData> {
    const text = `${job.headline} ${job.text}`.toLowerCase();

    // Kompetenser genom keyword matching
    const commonSkills = [
      // Tech
      'javascript', 'python', 'java', 'c#', 'typescript', 'react', 'vue', 'angular',
      'node.js', 'sql', 'git', 'docker', 'kubernetes', 'aws', 'azure', 'devops',
      // Bygg/VVS
      'svetsning', 'installation', 'renovering', 'nybyggnation', 'service',
      'felsökning', 'reparation', 'underhåll', 'projektering', 'cad', 'bim',
      // Verktyg
      'excel', 'word', 'powerpoint', 'visma', 'fortnox', 'sap', 'crm', 'erp',
      // Ledarskap
      'projektledning', 'teamledning', 'personalansvar', 'budgetansvar',
      // Allmänt
      'kundservice', 'försäljning', 'administration', 'kommunikation'
    ];

    const skills: Array<{ term: string; weight: number }> = [];

    for (const skill of commonSkills) {
      if (text.includes(skill)) {
        const occurrences = (text.match(new RegExp(skill, 'g')) || []).length;
        skills.push({
          term: skill,
          weight: Math.min(1.0, 0.5 + (occurrences * 0.15))
        });
      }
    }

    // Erfarenhetskrav
    let experienceRequired = undefined;
    const expMatch = text.match(/(\d+)[+]?\s*(år|years)/i);
    if (expMatch) {
      experienceRequired = {
        years: parseInt(expMatch[1]),
        level: parseInt(expMatch[1]) >= 5 ? 'senior' : parseInt(expMatch[1]) >= 2 ? 'mid' : 'junior',
        weight: 0.75
      };
    }

    // Utbildningsnivå
    let educationLevel = undefined;
    if (text.includes('högskola') || text.includes('universitet') || text.includes('civilingenjör')) {
      educationLevel = { level: 'universitet', weight: 0.8 };
    } else if (text.includes('gymnasie')) {
      educationLevel = { level: 'gymnasial', weight: 0.8 };
    }

    return {
      jobId: job.id,
      skills,
      experience_required: experienceRequired,
      education_level: educationLevel
    };
  }

  /**
   * Hämta cachade enrichments från databas
   */
  private async getCachedEnrichments(jobIds: string[]): Promise<Map<string, EnrichedJobData>> {
    const results = new Map<string, EnrichedJobData>();

    try {
      const { data } = await this.supabase
        .from('enriched_jobs')
        .select('*')
        .in('job_id', jobIds)
        .gt('expires_at', new Date().toISOString());

      if (data) {
        data.forEach((row: any) => {
          results.set(row.job_id, {
            jobId: row.job_id,
            occupations: row.occupations,
            skills: row.skills,
            competencies: row.competencies,
            experience_required: row.experience_required,
            education_level: row.education_level,
            languages: row.languages
          });
        });
      }
    } catch (error) {
      console.error('[AI Enrichment] Cache read error:', error);
    }

    return results;
  }

  /**
   * Spara enrichments till databas-cache
   */
  private async saveEnrichmentsToCache(enrichments: Map<string, EnrichedJobData>): Promise<void> {
    try {
      const cacheData = Array.from(enrichments.entries()).map(([jobId, data]) => ({
        job_id: jobId,
        job_headline: null, // Vi har inte headline här
        occupations: data.occupations || null,
        skills: data.skills || null,
        competencies: data.competencies || null,
        experience_required: data.experience_required || null,
        education_level: data.education_level || null,
        languages: data.languages || null,
        expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString() // 24h
      }));

      if (cacheData.length > 0) {
        await this.supabase.from('enriched_jobs').upsert(cacheData, { onConflict: 'job_id' });
        console.log(`[AI Enrichment] Saved ${cacheData.length} enrichments to cache`);
      }
    } catch (error) {
      console.error('[AI Enrichment] Cache save error:', error);
    }
  }
}

/**
 * Enhanced Taxonomy Service
 *
 * Förbättrad integration med Arbetsförmedlingens Taxonomy API:
 * - SSYK-koder med korrekt användning
 * - Related concepts (relaterade yrken)
 * - Kompetenser kopplade till yrken
 * - Cachning i databas (7 dagar)
 *
 * API Docs: https://taxonomy.api.jobtechdev.se/v1/taxonomy
 */

export interface TaxonomyData {
  primaryTerm: string;
  ssykCode: string | null;
  preferredLabel: string | null;
  alternativeLabels: string[];
  relatedOccupations: string[];
  competencies: string[];
  description?: string;
  // JobAd Links API filtering
  conceptId: string | null;           // occupation-name concept ID (ex: "5qT8_z9d_8rw")
  occupationFieldId: string | null;   // Samma som conceptId (för tydlighet)
  occupationGroupId: string | null;   // Bredare yrkesgrupp concept ID
}

const TAXONOMY_API = 'https://taxonomy.api.jobtechdev.se/v1/taxonomy';

export class TaxonomyEnhanced {
  private supabase: any;
  private cache = new Map<string, { data: TaxonomyData; timestamp: number }>();
  private CACHE_DURATION = 7 * 24 * 60 * 60 * 1000; // 7 dagar

  constructor(supabase: any) {
    this.supabase = supabase;
  }

  /**
   * Huvudfunktion: Berika ett yrke med fullständig taxonomy-data
   */
  async enrichOccupation(occupation: string): Promise<TaxonomyData> {
    // 1. Kolla databas-cache
    const cachedData = await this.getCachedFromDB(occupation);

    // Validera cache - använd bara om ssykCode finns
    if (cachedData && cachedData.ssykCode) {
      console.log(`[Taxonomy Enhanced] Cache HIT for "${occupation}" with SSYK ${cachedData.ssykCode}`);
      return cachedData;
    }

    // Om cache finns men saknar SSYK, hämta ny data
    if (cachedData && !cachedData.ssykCode) {
      console.log(`[Taxonomy Enhanced] Cache invalid (no SSYK code) for "${occupation}" - fetching fresh data`);
    } else {
      console.log(`[Taxonomy Enhanced] Cache MISS for "${occupation}" - fetching from API`);
    }

    // 2. Hämta från API (eller fallback)
    const taxonomyData = await this.fetchFromAPI(occupation);

    // 3. Spara till databas-cache (skriver över felaktig cache om den finns)
    await this.saveToDB(occupation, taxonomyData);

    return taxonomyData;
  }

  /**
   * Hämta relaterade yrken för bredare sökning
   */
  async getRelatedOccupations(occupation: string): Promise<string[]> {
    try {
      // Först hämta SSYK-kod för yrket
      const taxonomyData = await this.enrichOccupation(occupation);

      if (!taxonomyData.ssykCode) {
        console.warn(`[Taxonomy Enhanced] No SSYK code for "${occupation}", cannot get related occupations`);
        return [];
      }

      // Endpoint: /related/concepts/{concept_id}
      const conceptId = taxonomyData.ssykCode;
      const url = `${TAXONOMY_API}/related/concepts/${encodeURIComponent(conceptId)}?type=ssyk`;

      const response = await fetch(url, {
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        console.warn(`[Taxonomy Enhanced] Related concepts API error: ${response.status}`);
        return this.getFallbackRelatedOccupations(occupation);
      }

      const data = await response.json();

      // Parsa relaterade yrken
      const relatedOccupations: string[] = [];

      if (Array.isArray(data.related)) {
        for (const related of data.related.slice(0, 10)) { // Max 10 relaterade
          const label = related['taxonomy/preferred-label'] || related.label;
          if (label && label !== occupation) {
            relatedOccupations.push(label);
          }
        }
      }

      console.log(`[Taxonomy Enhanced] Found ${relatedOccupations.length} related occupations for "${occupation}"`);
      return relatedOccupations;

    } catch (error) {
      console.error(`[Taxonomy Enhanced] Error getting related occupations:`, error);
      return this.getFallbackRelatedOccupations(occupation);
    }
  }

  /**
   * Hämta från Taxonomy API
   * Använder occupation-name för JobAd Links filtering
   */
  private async fetchFromAPI(occupation: string): Promise<TaxonomyData> {
    try {
      // NYTT: Endpoint för occupation-name (inte ssyk)
      // Detta ger oss concept_id som JobAd Links API använder
      const searchUrl = `${TAXONOMY_API}/specific/concepts/occupation-name?preferred-label=${encodeURIComponent(occupation)}&limit=5`;

      const response = await fetch(searchUrl, {
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        console.warn(`[Taxonomy Enhanced] API error (${response.status}) for "${occupation}"`);
        return this.createFallbackData(occupation);
      }

      const data = await response.json();

      if (!data || data.length === 0) {
        console.warn(`[Taxonomy Enhanced] No occupation-name data found for "${occupation}"`);
        return this.createFallbackData(occupation);
      }

      const bestMatch = data[0];

      // Taxonomy API response format
      const conceptId = bestMatch['id'] || null;  // HUVUDSAKLIG: concept_id för JobAd Links
      const preferredLabel = bestMatch['taxonomy/preferred-label'] || null;
      const alternativeLabels = bestMatch['taxonomy/alternative-labels'] || [];
      const description = bestMatch['taxonomy/description'] || undefined;

      // Hämta SSYK-kod via concept ID (för backward compatibility)
      let ssykCode: string | null = null;
      let occupationGroupId: string | null = null;

      if (conceptId) {
        // Hämta SSYK via /concepts/{conceptId}/related
        const ssykData = await this.getSSYKForOccupation(conceptId);
        ssykCode = ssykData.ssykCode;
        occupationGroupId = ssykData.occupationGroupId;
      }

      // Hämta kompetenser för detta yrke
      let competencies: string[] = [];
      if (conceptId) {
        competencies = await this.getCompetenciesForOccupation(conceptId);
      }

      console.log(`[Taxonomy Enhanced] "${occupation}" → concept_id: ${conceptId}, SSYK: ${ssykCode}, ${alternativeLabels.length} synonymer`);

      return {
        primaryTerm: occupation,
        ssykCode,
        preferredLabel,
        alternativeLabels,
        relatedOccupations: [], // Fylls i senare via getRelatedOccupations()
        competencies,
        description,
        conceptId,
        occupationFieldId: conceptId, // Samma som conceptId
        occupationGroupId
      };

    } catch (error) {
      console.error(`[Taxonomy Enhanced] API error for "${occupation}":`, error);
      return this.createFallbackData(occupation);
    }
  }

  /**
   * Hämta SSYK-kod och occupation-group för ett occupation-name concept
   */
  private async getSSYKForOccupation(conceptId: string): Promise<{ ssykCode: string | null; occupationGroupId: string | null }> {
    try {
      // Hämta related concepts för occupation-name
      const url = `${TAXONOMY_API}/concepts/${encodeURIComponent(conceptId)}/related`;

      const response = await fetch(url, {
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        return { ssykCode: null, occupationGroupId: null };
      }

      const data = await response.json();
      let ssykCode: string | null = null;
      let occupationGroupId: string | null = null;

      if (Array.isArray(data.related)) {
        for (const rel of data.related) {
          const type = rel['taxonomy/type'];

          // Leta efter SSYK-relation
          if (type === 'ssyk-level-4' && rel['taxonomy/ssyk-code-2012']) {
            ssykCode = rel['taxonomy/ssyk-code-2012'];
          }

          // Leta efter occupation-group
          if (type === 'occupation-group' && rel['id']) {
            occupationGroupId = rel['id'];
          }
        }
      }

      return { ssykCode, occupationGroupId };

    } catch (error) {
      console.error('[Taxonomy Enhanced] Error fetching SSYK for occupation:', error);
      return { ssykCode: null, occupationGroupId: null };
    }
  }

  /**
   * Hämta kompetenser för ett yrke (via concept ID)
   */
  private async getCompetenciesForOccupation(conceptId: string): Promise<string[]> {
    try {
      // Endpoint kan variera - justera efter faktisk API-dokumentation
      const url = `${TAXONOMY_API}/concepts/${encodeURIComponent(conceptId)}/related?type=skill`;

      const response = await fetch(url, {
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        return [];
      }

      const data = await response.json();
      const competencies: string[] = [];

      if (Array.isArray(data.related)) {
        for (const comp of data.related.slice(0, 20)) { // Max 20 kompetenser
          const label = comp['taxonomy/preferred-label'] || comp.label;
          if (label) {
            competencies.push(label);
          }
        }
      }

      return competencies;

    } catch (error) {
      console.error('[Taxonomy Enhanced] Error fetching competencies:', error);
      return [];
    }
  }

  /**
   * Fallback: Manuell data om API failar
   */
  private createFallbackData(occupation: string): TaxonomyData {
    const manualData: Record<string, Partial<TaxonomyData>> = {
      'rörmokare': {
        ssykCode: '7126',
        alternativeLabels: ['vvs-montör', 'vs-montör', 'rörläggare', 'vvs-installatör'],
        competencies: ['installation', 'reparation', 'service', 'rörinstallation']
      },
      'butikschef': {
        ssykCode: '1420',
        alternativeLabels: ['store manager', 'butiksansvarig', 'butiksföreståndare'],
        competencies: ['ledarskap', 'försäljning', 'personalansvar', 'kundservice']
      },
      'elektriker': {
        ssykCode: '7411',
        alternativeLabels: ['elmontör', 'elinstallatör', 'eltekniker'],
        competencies: ['elinstallation', 'felsökning', 'service']
      },
      'snickare': {
        ssykCode: '7115',
        alternativeLabels: ['byggsnickare', 'möbelsnickare', 'inredningssnickare'],
        competencies: ['byggarbete', 'renovering', 'träbearbetning']
      },
      'systemutvecklare': {
        ssykCode: '2512',
        alternativeLabels: ['mjukvaruutvecklare', 'utvecklare', 'programmerare'],
        competencies: ['programmering', 'systemdesign', 'databashantering']
      }
    };

    const fallback = manualData[occupation.toLowerCase()] || {};

    return {
      primaryTerm: occupation,
      ssykCode: fallback.ssykCode || null,
      preferredLabel: occupation,
      alternativeLabels: fallback.alternativeLabels || [],
      relatedOccupations: [],
      competencies: fallback.competencies || [],
      conceptId: null,
      occupationFieldId: null,
      occupationGroupId: null
    };
  }

  /**
   * Fallback för relaterade yrken
   */
  private getFallbackRelatedOccupations(occupation: string): string[] {
    const relatedMap: Record<string, string[]> = {
      'butikschef': ['butikssäljare', 'försäljningschef', 'säljare', 'butiksmedarbetare'],
      'rörmokare': ['ventilationsmontör', 'vvs-montör', 'fastighetstekniker'],
      'elektriker': ['elmontör', 'servicetekniker', 'drifttekniker'],
      'systemutvecklare': ['mjukvaruutvecklare', 'frontend-utvecklare', 'backend-utvecklare', 'fullstack-utvecklare'],
      'sjuksköterska': ['undersköterska', 'specialist sjuksköterska', 'vårdpersonal']
    };

    return relatedMap[occupation.toLowerCase()] || [];
  }

  /**
   * Hämta från databas-cache
   */
  private async getCachedFromDB(occupation: string): Promise<TaxonomyData | null> {
    try {
      const { data, error } = await this.supabase
        .from('enriched_occupations')
        .select('*')
        .eq('occupation', occupation.toLowerCase())
        .gt('expires_at', new Date().toISOString())
        .single();

      if (error || !data) return null;

      return {
        primaryTerm: data.occupation,
        ssykCode: data.ssyk_code,
        preferredLabel: data.preferred_label,
        alternativeLabels: data.alternative_labels || [],
        relatedOccupations: data.related_occupations || [],
        competencies: data.competencies || [],
        conceptId: data.concept_id || null,
        occupationFieldId: data.concept_id || null,
        occupationGroupId: data.occupation_group_id || null
      };

    } catch {
      return null;
    }
  }

  /**
   * Spara till databas-cache
   */
  private async saveToDB(occupation: string, taxonomyData: TaxonomyData): Promise<void> {
    try {
      const cacheData = {
        occupation: occupation.toLowerCase(),
        ssyk_code: taxonomyData.ssykCode,
        preferred_label: taxonomyData.preferredLabel,
        alternative_labels: taxonomyData.alternativeLabels,
        related_occupations: taxonomyData.relatedOccupations,
        competencies: taxonomyData.competencies,
        concept_id: taxonomyData.conceptId,  // NYTT: För JobAd Links
        occupation_group_id: taxonomyData.occupationGroupId,  // NYTT: För bredare sökning
        trending_skills: null,
        historical_data: null,
        education_matches: [],
        expires_at: new Date(Date.now() + this.CACHE_DURATION).toISOString()
      };

      await this.supabase.from('enriched_occupations').upsert(cacheData, {
        onConflict: 'occupation'
      });

      console.log(`[Taxonomy Enhanced] Saved "${occupation}" to cache (concept_id: ${taxonomyData.conceptId})`);

    } catch (error) {
      console.error('[Taxonomy Enhanced] Cache save error:', error);
    }
  }
}

/**
 * Scoring Engine V2
 *
 * Förbättrad scoring-algoritm med 6 faktorer (max 100 poäng):
 * 1. SSYK-match (35p) - Exakt eller relaterad SSYK-kod
 * 2. Yrkestitel (20p) - Inkl. synonymer från taxonomy
 * 3. Erfarenhet (15p) - CV-erfarenhet vs jobbkrav
 * 4. Kompetenser (15p) - AI-matchade från enrichments
 * 5. Geografi (10p) - Avstånd eller remote
 * 6. Utbildning (5p) - Utbildningsnivå vs krav
 */

import { EnrichedJobData } from './ai-enrichment.ts';
import { TaxonomyData } from './taxonomy-enhanced.ts';

export interface ScoringInput {
  cvData: any;
  cvOccupations: string[];
  cvLocations: string[];
  taxonomyData: TaxonomyData | null;
  job: any;
  enrichedJob: EnrichedJobData | null;
}

export interface ScoringResult {
  total: number;
  breakdown: {
    ssykMatch: number;          // 0-35p
    occupationMatch: number;    // 0-20p
    experienceMatch: number;    // 0-15p
    competenciesMatch: number;  // 0-15p
    geography: number;          // 0-10p
    educationMatch: number;     // 0-5p
  };
  explanation: string[];
  distance?: number;
}

