const REMOTE_KEYWORDS = ["distans", "remote", "hemarbete", "hemifrån"];

export class ScoringEngineV2 {
  /**
   * Huvudfunktion: Beräkna total score för ett jobb
   */
  calculateScore(input: ScoringInput): ScoringResult {
    const breakdown = {
      ssykMatch: 0,
      occupationMatch: 0,
      experienceMatch: 0,
      competenciesMatch: 0,
      geography: 0,
      educationMatch: 0
    };
    const explanation: string[] = [];
    let distance: number | undefined;

    // ============================================================================
    // FAKTOR 1: SSYK/Occupation-match (35p)
    // ============================================================================
    // NYTT: Prioritera JobAd Links occupation_field data över AI enrichment
    // JobAd Links har redan strukturerad occupation data direkt från källan

    // STRATEGI 1A: JobAd Links occupation_field match (högsta prioritet - 35p)
    if (input.taxonomyData?.conceptId && input.job.occupation_field?.concept_id) {
      if (input.job.occupation_field.concept_id === input.taxonomyData.conceptId) {
        breakdown.ssykMatch = 35;
        explanation.push(`✅ Exakt occupation-field match (JobAd Links): ${input.job.occupation_field.label} (35p)`);
      }
    }

    // STRATEGI 1B: JobAd Links occupation_group match (bredare - 25p)
    if (breakdown.ssykMatch === 0 && input.taxonomyData?.occupationGroupId && input.job.occupation_group?.concept_id) {
      if (input.job.occupation_group.concept_id === input.taxonomyData.occupationGroupId) {
        breakdown.ssykMatch = 25;
        explanation.push(`✅ Occupation-group match (JobAd Links): ${input.job.occupation_group.label} (25p)`);
      }
    }

    // STRATEGI 1C: SSYK-match från AI enrichment (fallback - används bara om JobAd Links data saknas)
    if (breakdown.ssykMatch === 0 && input.taxonomyData?.ssykCode && input.enrichedJob?.occupations) {
      // Exakt match: samma 4-siffrig SSYK-kod från AI enrichment
      for (const jobOcc of input.enrichedJob.occupations) {
        if (jobOcc.ssyk_code === input.taxonomyData.ssykCode) {
          const confidence = jobOcc.weight || 0.5;
          const weightedScore = Math.round(30 * confidence); // Något lägre än JobAd Links (30p vs 35p)
          breakdown.ssykMatch = weightedScore;
          explanation.push(`✅ Exakt SSYK-match (AI): ${input.taxonomyData.ssykCode} (${weightedScore}p, confidence: ${(confidence * 100).toFixed(0)}%)`);
          break;
        }
      }

      // Partiell match: samma 3-siffrig SSYK-kod (yrkesgrupp)
      if (breakdown.ssykMatch === 0) {
        const userSSYK3 = input.taxonomyData.ssykCode.substring(0, 3);
        for (const jobOcc of input.enrichedJob.occupations) {
          if (jobOcc.ssyk_code?.substring(0, 3) === userSSYK3) {
            const confidence = jobOcc.weight || 0.5;
            const weightedScore = Math.round(20 * confidence);
            breakdown.ssykMatch = weightedScore;
            explanation.push(`✅ Samma yrkesgrupp (AI SSYK-3): ${userSSYK3} (${weightedScore}p, confidence: ${(confidence * 100).toFixed(0)}%)`);
            break;
          }
        }
      }
    }

    // ============================================================================
    // FAKTOR 2: Yrkestitel-matchning (20p)
    // ============================================================================
    if (input.cvOccupations.length > 0) {
      const cvOccupation = input.cvOccupations[0].toLowerCase();
      const jobOccupation = (input.job.occupation?.label || '').toLowerCase();
      const jobHeadline = (input.job.headline || '').toLowerCase();

      if (jobOccupation === cvOccupation) {
        breakdown.occupationMatch = 20;
        explanation.push(`✅ Exakt yrkestitel: ${input.job.occupation?.label} (20p)`);
      } else if (jobOccupation.includes(cvOccupation) || cvOccupation.includes(jobOccupation)) {
        breakdown.occupationMatch = 16;
        explanation.push(`✅ Liknande yrkestitel (16p)`);
      } else if (jobHeadline.includes(cvOccupation)) {
        breakdown.occupationMatch = 12;
        explanation.push(`✅ Yrke i rubrik (12p)`);
      }

      // Kolla synonymer från taxonomy
      if (breakdown.occupationMatch === 0 && input.taxonomyData?.alternativeLabels) {
        for (const synonym of input.taxonomyData.alternativeLabels) {
          if (jobOccupation.includes(synonym.toLowerCase()) || jobHeadline.includes(synonym.toLowerCase())) {
            breakdown.occupationMatch = 14;
            explanation.push(`✅ Synonym-match: ${synonym} (14p)`);
            break;
          }
        }
      }

      // Yrkesgrupp som fallback
      if (breakdown.occupationMatch === 0 && input.job.occupation_group?.label) {
        const jobGroup = input.job.occupation_group.label.toLowerCase();
        if ((jobGroup.includes('chef') && cvOccupation.includes('chef')) ||
            (jobGroup.includes('handel') && (cvOccupation.includes('butik') || cvOccupation.includes('försälj')))) {
          breakdown.occupationMatch = 8;
          explanation.push(`✅ Samma yrkesgrupp: ${input.job.occupation_group.label} (8p)`);
        }
      }
    }

    // ============================================================================
    // FAKTOR 3: Erfarenhet (15p)
    // ============================================================================
    const yearsExperience = this.calculateRelevantExperience(input);

    if (yearsExperience >= 10) {
      breakdown.experienceMatch = 15;
      explanation.push(`✅ ${Math.floor(yearsExperience)} års erfarenhet (15p)`);
    } else if (yearsExperience >= 5) {
      breakdown.experienceMatch = 13;
      explanation.push(`✅ ${Math.floor(yearsExperience)} års erfarenhet (13p)`);
    } else if (yearsExperience >= 3) {
      breakdown.experienceMatch = 10;
      explanation.push(`✅ ${Math.floor(yearsExperience)} års erfarenhet (10p)`);
    } else if (yearsExperience >= 1) {
      breakdown.experienceMatch = 7;
      explanation.push(`✅ ${Math.floor(yearsExperience)} års erfarenhet (7p)`);
    } else if (yearsExperience > 0) {
      breakdown.experienceMatch = 3;
      explanation.push(`⚠️ <1 års erfarenhet (3p)`);
    }

    // ============================================================================
    // FAKTOR 4: Kompetenser (15p) - NY VIKTAD FAKTOR
    // ============================================================================
    if (input.enrichedJob?.skills && input.cvData.structuredCV?.skills) {
      const matchedSkills = this.matchSkills(
        input.cvData.structuredCV.skills,
        input.enrichedJob.skills
      );

      if (matchedSkills >= 5) {
        breakdown.competenciesMatch = 15;
        explanation.push(`✅ ${matchedSkills} matchande kompetenser (15p)`);
      } else if (matchedSkills >= 3) {
        breakdown.competenciesMatch = 12;
        explanation.push(`✅ ${matchedSkills} kompetenser (12p)`);
      } else if (matchedSkills >= 2) {
        breakdown.competenciesMatch = 8;
        explanation.push(`✅ ${matchedSkills} kompetenser (8p)`);
      } else if (matchedSkills >= 1) {
        breakdown.competenciesMatch = 4;
        explanation.push(`✅ ${matchedSkills} kompetens (4p)`);
      }
    }

    // ============================================================================
    // FAKTOR 5: Geografi (10p) - JUSTERAD VIKTNING
    // ============================================================================
    const isRemote = this.checkIfRemote(input.job);

    if (isRemote) {
      breakdown.geography = 10;
      explanation.push(`✅ Remote-jobb (10p)`);
    } else if (input.cvLocations.length > 0 && input.job.workplace_address?.municipality) {
      const result = this.calculateGeographyScore(input.cvLocations[0], input.job.workplace_address.municipality);
      breakdown.geography = result.score;
      distance = result.distance;
      if (result.explanation) {
        explanation.push(result.explanation);
      }
    }

    // ============================================================================
    // FAKTOR 6: Utbildning (5p) - NY FAKTOR
    // ============================================================================
    if (input.enrichedJob?.education_level && input.cvData.structuredCV?.education) {
      const cvEducationLevel = this.getHighestEducationLevel(input.cvData.structuredCV.education);
      const jobRequiredLevel = input.enrichedJob.education_level.level;

      const educationScore = this.compareEducationLevels(cvEducationLevel, jobRequiredLevel);

      if (educationScore >= 1.0) {
        breakdown.educationMatch = 5;
        explanation.push(`✅ Utbildningsnivå matchar eller överträffar krav (5p)`);
      } else if (educationScore >= 0.8) {
        breakdown.educationMatch = 3;
        explanation.push(`✅ Liknande utbildningsnivå (3p)`);
      } else if (educationScore >= 0.5) {
        breakdown.educationMatch = 1;
        explanation.push(`⚠️ Lägre utbildningsnivå än krav (1p)`);
      }
    }

    // ============================================================================
    // Beräkna total score
    // ============================================================================
    const total = Math.min(
      100,
      Math.round(
        breakdown.ssykMatch +
        breakdown.occupationMatch +
        breakdown.experienceMatch +
        breakdown.competenciesMatch +
        breakdown.geography +
        breakdown.educationMatch
      )
    );

    return { total, breakdown, explanation, distance };
  }

  /**
   * Beräkna relevant erfarenhet för jobbet
   */
  private calculateRelevantExperience(input: ScoringInput): number {
    let totalYears = 0;

    if (!input.cvData.structuredCV?.experience) return 0;

    const jobOccupation = (input.job.occupation?.label || '').toLowerCase();

    for (const exp of input.cvData.structuredCV.experience) {
      const position = (exp.position || '').toLowerCase();

      // Kolla om erfarenheten är relevant
      const isRelevant =
        position.includes(jobOccupation) ||
        jobOccupation.includes(position) ||
        (position.includes('chef') && jobOccupation.includes('chef')) ||
        (position.includes('butik') && jobOccupation.includes('butik')) ||
        (position.includes('vvs') && jobOccupation.includes('vvs'));

      if (isRelevant) {
        try {
          const parseDate = (dateStr: string) => {
            const parts = dateStr.split('/');
            if (parts.length === 2) {
              return new Date(parseInt(parts[1]), parseInt(parts[0]) - 1);
            }
            return null;
          };

          const startDate = parseDate(exp.startDate);
          const endDate = exp.endDate ? parseDate(exp.endDate) : new Date();

          if (startDate && endDate) {
            const years = (endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24 * 365.25);
            totalYears += years;
          }
        } catch {
          // Skip om datum inte kan parsas
        }
      }
    }

    return totalYears;
  }

  /**
   * Matcha kompetenser mellan CV och jobb
   */
  private matchSkills(cvSkills: any[], jobSkills: Array<{ term: string; weight: number }>): number {
    const cvSkillSet = new Set<string>();

    // Extrahera alla CV-skills
    for (const skillItem of cvSkills) {
      if (typeof skillItem === 'string') {
        cvSkillSet.add(skillItem.toLowerCase());
      } else if (skillItem.skills) {
        for (const skill of skillItem.skills) {
          cvSkillSet.add(skill.toLowerCase());
        }
      }
    }

    // Räkna matchningar
    let matches = 0;
    for (const jobSkill of jobSkills) {
      const term = jobSkill.term.toLowerCase();
      if (cvSkillSet.has(term)) {
        matches++;
      }
    }

    return matches;
  }

  /**
   * Beräkna geografisk score
   */
  private calculateGeographyScore(userLocation: string, jobLocation: string): {
    score: number;
    distance?: number;
    explanation?: string;
  } {
    const userCoords = this.getMunicipalityCoords(userLocation);
    const jobCoords = this.getMunicipalityCoords(jobLocation);

    if (!userCoords || !jobCoords) {
      return { score: 5 }; // Default score om koordinater saknas
    }

    const distance = this.calculateDistance(
      userCoords.lat, userCoords.lon,
      jobCoords.lat, jobCoords.lon
    );

    if (distance < 10) {
      return { score: 10, distance, explanation: `✅ Samma stad: ${Math.round(distance)}km (10p)` };
    } else if (distance < 30) {
      return { score: 9, distance, explanation: `✅ <30km: ${Math.round(distance)}km (9p)` };
    } else if (distance < 50) {
      return { score: 7, distance, explanation: `⚠️ <50km: ${Math.round(distance)}km (7p)` };
    } else if (distance < 100) {
      return { score: 4, distance, explanation: `⚠️ <100km: ${Math.round(distance)}km (4p)` };
    } else {
      return { score: 1, distance, explanation: `❌ För långt: ${Math.round(distance)}km (1p)` };
    }
  }

  /**
   * Hitta högsta utbildningsnivå i CV
   */
  private getHighestEducationLevel(educations: any[]): string {
    const levels = ['universitet', 'eftergymnasial', 'gymnasial', 'grundskola'];

    for (const education of educations) {
      const degree = (education.degree || '').toLowerCase();
      const institution = (education.institution || '').toLowerCase();

      if (degree.includes('doktor') || degree.includes('phd')) return 'doktor';
      if (degree.includes('master') || degree.includes('magister')) return 'universitet';
      if (degree.includes('kandidat') || degree.includes('högskola') || institution.includes('universitet')) return 'universitet';
      if (degree.includes('yrkeshögskola') || degree.includes('komvux')) return 'eftergymnasial';
      if (degree.includes('gymnasie')) return 'gymnasial';
    }

    return 'gymnasial'; // Default
  }

  /**
   * Jämför utbildningsnivåer (returnerar 0-1)
   */
  private compareEducationLevels(cvLevel: string, requiredLevel: string): number {
    const levelRanking: Record<string, number> = {
      'grundskola': 1,
      'gymnasial': 2,
      'eftergymnasial': 3,
      'universitet': 4,
      'doktor': 5
    };

    const cvRank = levelRanking[cvLevel] || 2;
    const reqRank = levelRanking[requiredLevel] || 2;

    if (cvRank >= reqRank) return 1.0;
    if (cvRank === reqRank - 1) return 0.8;
    return 0.5;
  }

  /**
   * Kolla om jobbet är remote
   */
  private checkIfRemote(job: any): boolean {
    const text = `${job.headline} ${job.description?.text || ''}`.toLowerCase();
    return REMOTE_KEYWORDS.some(keyword => text.includes(keyword));
  }

  /**
   * Hämta koordinater för kommun
   */
  private getMunicipalityCoords(location: string): { lat: number; lon: number } | null {
    if (!location) return null;
    const normalized = location.toLowerCase().trim();

    for (const [city, coords] of Object.entries(SWEDISH_MUNICIPALITIES)) {
      if (normalized.includes(city)) return coords;
    }

    return null;
  }

  /**
   * Beräkna avstånd mellan två koordinater (Haversine)
   */
  private calculateDistance(lat1: number, lon1: number, lat2: number, lon2: number): number {
    const R = 6371; // Earth radius in km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;

    const a =
      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
      Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
      Math.sin(dLon / 2) * Math.sin(dLon / 2);

    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
  }
}

/**
 * Multi-Source Job Aggregator
 *
 * Aggregerar jobb från JobAd Links API för maximal täckning:
 * - 30% fler jobb än Platsbanken
 * - Inkluderar LinkedIn, Indeed, StepStone, Monster, etc.
 * - Strukturerad occupation data (occupation_field, occupation_group)
 * - Optimerad filtrering med occupation-field parameter
 */

export interface AggregationParams {
  primaryOccupation: string;
  taxonomyData: any;
  relatedOccupations: string[];
  cvEducations: any[];
  userLocation: string;
  customQuery?: string;
  maxJobsPerQuery: number;
  maxTotalJobs: number;
}

interface Job {
  id: string;
  headline: string;
  description: { text: string };
  employer: { name: string };
  workplace_address?: { municipality?: string };
  publication_date?: string;
  application_deadline?: string;
  application_url?: string;
  occupation?: { label?: string; concept_id?: string };
  occupation_group?: { label?: string; concept_id?: string };
  occupation_field?: { label?: string; concept_id?: string }; // NYTT: JobAd Links occupation_field
  source: string; // 'jobad-links', 'jobsearch', 'education-match'
}

const JOBLINKS_API = 'https://links.api.jobtechdev.se/joblinks';

export class MultiSourceAggregator {
  /**
   * Huvudfunktion: Aggregera jobb från alla källor
   */
  async aggregateJobs(params: AggregationParams): Promise<Job[]> {
    console.log('[Aggregator] Starting multi-source aggregation...');

    const allJobs: Job[] = [];
    const seenIds = new Set<string>();

    // ============================================================================
    // STRATEGI 1: Custom Query (Användaren har angett specifik sökning)
    // ============================================================================
    if (params.customQuery) {
      console.log(`[Aggregator] Using custom query: "${params.customQuery}"`);
      const customJobs = await this.fetchWithPagination({
        q: params.customQuery,
        limit: 100
      }, 10); // 10 pages = 1000 jobs max

      this.addUniqueJobs(allJobs, customJobs, seenIds, 'custom-query');
      console.log(`[Aggregator] Custom query: ${customJobs.length} jobs`);

      return allJobs.slice(0, params.maxTotalJobs);
    }

    // ============================================================================
    // STRATEGI 2: occupation-field sökning (Primär strategi) - ULTRA TIGHT FILTER
    // ============================================================================
    // NYTT: Använder occupation-field parameter istället för q=ssyk:xxx
    // Detta ger EXAKT matchning på yrkesfält från Taxonomy API
    if (params.taxonomyData?.conceptId) {
      console.log(`[Aggregator] occupation-field search: ${params.taxonomyData.conceptId} (${params.primaryOccupation})`);

      // ULTRA TIGHT FILTER: occupation-field parameter med concept_id
      // Detta är 100x mer precist än q=ssyk:xxx som returnerade 0 resultat
      const occupationJobs = await this.fetchWithPagination({
        'occupation-field': params.taxonomyData.conceptId,
        limit: 100
      }, 15); // Max 1500 jobb från occupation-field sökning (30% fler än Platsbanken)

      this.addUniqueJobs(allJobs, occupationJobs, seenIds, 'occupation-field-primary');
      console.log(`[Aggregator] occupation-field primary: ${occupationJobs.length} jobs (${allJobs.length} unique)`);

      // EARLY RETURN: Om vi har nog occupation-matchade jobb, skippa bredare sökningar
      if (allJobs.length >= 500) {
        console.log(`[Aggregator] ✅ Found ${allJobs.length} occupation-matched jobs - skipping broader searches for optimal performance`);
        return allJobs.slice(0, params.maxTotalJobs);
      }
    }

    // ============================================================================
    // STRATEGI 2B: occupation-group fallback (om för få occupation-field resultat)
    // ============================================================================
    // Om occupation-field gav <500 jobb, prova bredare occupation-group
    if (allJobs.length < 500 && params.taxonomyData?.occupationGroupId) {
      console.log(`[Aggregator] Only ${allJobs.length} occupation-field jobs - expanding with occupation-group: ${params.taxonomyData.occupationGroupId}`);

      const groupJobs = await this.fetchWithPagination({
        'occupation-group': params.taxonomyData.occupationGroupId,
        limit: 100
      }, 5); // Max 500 jobb från occupation-group

      this.addUniqueJobs(allJobs, groupJobs, seenIds, 'occupation-group');
      console.log(`[Aggregator] occupation-group: ${groupJobs.length} jobs (${allJobs.length} unique)`);
    }

    // ============================================================================
    // STRATEGI 3: Synonymer och alternativa titlar (CONDITIONAL)
    // ============================================================================
    // KÖR ENDAST om för få SSYK-jobb hittades (<300)
    if (allJobs.length < 300 && params.taxonomyData?.alternativeLabels?.length > 0) {
      console.log(`[Aggregator] Only ${allJobs.length} SSYK jobs - expanding with ${params.taxonomyData.alternativeLabels.length} synonyms...`);

      const synonymQuery = params.taxonomyData.alternativeLabels
        .slice(0, 5) // Max 5 synonymer
        .map((label: string) => `"${label}"`)
        .join(' OR ');

      const synonymJobs = await this.fetchWithPagination({
        q: synonymQuery,
        limit: 100
      }, 3); // Reducerat från 5 → 3 pages (300 jobb max)

      this.addUniqueJobs(allJobs, synonymJobs, seenIds, 'synonyms');
      console.log(`[Aggregator] Synonyms: ${synonymJobs.length} jobs (${allJobs.length} unique)`);
    }

    // ============================================================================
    // STRATEGI 4: Relaterade yrken (CONDITIONAL - lägre prioritet)
    // ============================================================================
    // KÖR ENDAST om fortfarande för få jobb (<500)
    if (allJobs.length < 500 && params.relatedOccupations.length > 0) {
      console.log(`[Aggregator] Only ${allJobs.length} jobs - adding ${params.relatedOccupations.length} related occupations...`);

      const relatedQuery = params.relatedOccupations
        .slice(0, 3) // Max 3 relaterade
        .map(occ => `"${occ}"`)
        .join(' OR ');

      const relatedJobs = await this.fetchWithPagination({
        q: relatedQuery,
        limit: 100
      }, 2); // Reducerat från 3 → 2 pages (200 jobb max)

      this.addUniqueJobs(allJobs, relatedJobs, seenIds, 'related-occupations');
      console.log(`[Aggregator] Related: ${relatedJobs.length} jobs (${allJobs.length} unique)`);
    }

    // ============================================================================
    // STRATEGI 5 & 6: REMOVED (Education & Fallback)
    // ============================================================================
    // Education-based och fallback searches har tagits bort för att:
    // 1. Utbildningssökning är för bred och ger låg relevans
    // 2. Fallback-sökning ger för många irrelevanta jobb
    // 3. Med bra SSYK-data + synonymer + related är dessa överflödiga
    // 4. Minskar processing tid och förbättrar relevans

    console.log(`[Aggregator] ✅ Total aggregated: ${allJobs.length} unique jobs from all sources`);
    return allJobs.slice(0, params.maxTotalJobs);
  }

  /**
   * Hämta jobb med pagination (upp till maxPages sidor)
   * NYTT: Använder JobAd Links API med occupation-field och occupation-group parametrar
   */
  private async fetchWithPagination(
    query: any,
    maxPages: number
  ): Promise<Job[]> {
    const LIMIT = 100;
    const allJobs: Job[] = [];

    for (let page = 0; page < maxPages; page++) {
      const offset = page * LIMIT;

      try {
        const queryParams = new URLSearchParams();

        // JobAd Links API parametrar (olika från JobSearch API)
        if (query['occupation-field']) queryParams.append('occupation-field', query['occupation-field']);
        if (query['occupation-group']) queryParams.append('occupation-group', query['occupation-group']);
        if (query.q) queryParams.append('q', query.q); // Fallback för custom queries
        if (query.municipality) queryParams.append('municipality', query.municipality);

        queryParams.append('limit', LIMIT.toString());
        queryParams.append('offset', offset.toString());

        const url = `${JOBLINKS_API}?${queryParams.toString()}`;
        const response = await fetch(url, {
          headers: { 'Accept': 'application/json' }
        });

        if (!response.ok) {
          console.error(`[Aggregator] API error (${response.status}) at page ${page + 1}`);
          break;
        }

        const data = await response.json();
        const jobs = data.hits || [];

        if (jobs.length === 0) {
          console.log(`[Aggregator] No more results at page ${page + 1}`);
          break;
        }

        // Konvertera till internt format
        const convertedJobs = jobs.map((job: any) => this.convertToInternalFormat(job));
        allJobs.push(...convertedJobs);

        console.log(`[Aggregator] Page ${page + 1}/${maxPages}: ${jobs.length} jobs`);

        // Om vi fick färre än limit, vi har nått slutet
        if (jobs.length < LIMIT) {
          console.log(`[Aggregator] Reached end at page ${page + 1}`);
          break;
        }

        // Rate limiting: vänta lite mellan requests
        if (page < maxPages - 1) {
          await new Promise(resolve => setTimeout(resolve, 100));
        }

      } catch (error) {
        console.error(`[Aggregator] Error at page ${page + 1}:`, error);
        break;
      }
    }

    return allJobs;
  }

  /**
   * Lägg till unika jobb (undvik dubbletter)
   */
  private addUniqueJobs(
    allJobs: Job[],
    newJobs: Job[],
    seenIds: Set<string>,
    source: string
  ): void {
    let added = 0;
    for (const job of newJobs) {
      if (!seenIds.has(job.id)) {
        seenIds.add(job.id);
        allJobs.push({ ...job, source });
        added++;
      }
    }
    console.log(`[Aggregator] Added ${added} unique jobs from ${source}`);
  }

  /**
   * Konvertera JobAd Links API-svar till internt format
   * JobAd Links response format skiljer sig från JobSearch API
   */
  private convertToInternalFormat(job: any): Job {
    // JobAd Links använder 'brief' istället för 'description.text'
    const descriptionText = job.brief || job.description?.text || '';

    // workplace_addresses är en array i JobAd Links
    const workplaceAddress = Array.isArray(job.workplace_addresses) && job.workplace_addresses.length > 0
      ? job.workplace_addresses[0]
      : job.workplace_address;

    // source_links array innehåller ansökningslänkar från olika källor
    let applicationUrl = job.application_url || job.webpage_url;
    if (!applicationUrl && Array.isArray(job.source_links)) {
      const arbetsformedlingenLink = job.source_links.find((link: any) => link.source === 'arbetsformedlingen');
      applicationUrl = arbetsformedlingenLink?.url || job.source_links[0]?.url;
    }

    // JobAd Links har occupation_field (mer specifikt) och occupation_group (bredare)
    const occupationField = job.occupation_field || job.occupation;
    const occupationGroup = job.occupation_group;

    return {
      id: job.id,
      headline: job.headline || job.title || 'Okänd titel',
      description: { text: descriptionText },
      employer: { name: job.employer?.name || job.company || 'Okänd arbetsgivare' },
      workplace_address: workplaceAddress,
      publication_date: job.publication_date || job.published_at,
      application_deadline: job.application_deadline || job.deadline,
      application_url: applicationUrl,
      occupation: occupationField,
      occupation_group: occupationGroup,
      occupation_field: occupationField, // NYTT: Preserve occupation_field för scoring
      source: 'jobad-links'
    };
  }

  /**
   * Extrahera sökbart nyckelord från utbildning
   */
  private extractEducationKeyword(education: any): string | null {
    const degree = education.degree || '';
    const institution = education.institution || '';
    const description = education.description || '';

    const text = `${degree} ${institution} ${description}`.toLowerCase();

    // Vanliga utbildningskategorier
    const keywords = [
      'vvs', 'el', 'elektriker', 'bygg', 'snickare', 'data', 'it', 'systemvetenskap',
      'ekonomi', 'handel', 'företagsekonomi', 'redovisning', 'juridik', 'jur.kand',
      'sjuksköterska', 'vård', 'omvårdnad', 'läkare', 'medicin', 'lärare', 'pedagogik'
    ];

    for (const keyword of keywords) {
      if (text.includes(keyword)) {
        return keyword;
      }
    }

    // Om inget nyckelord hittades, returnera degree om det finns
    return degree.length > 3 ? degree : null;
  }
}

/**
 * CV Utility Functions
 *
 * Hjälpfunktioner för att extrahera data från CV-analyser
 */

/**
 * Extrahera yrken från CV-data
 */
export function extractOccupations(cvData: any): string[] {
  const occupations: string[] = [];

  if (cvData.structuredCV?.experience) {
    cvData.structuredCV.experience.forEach((exp: any) => {
      if (exp.position) {
        occupations.push(exp.position.toLowerCase());
      }
    });
  }

  // Deduplicate och returnera
  return [...new Set(occupations)];
}

/**
 * Extrahera geografiska platser från CV
 */
export function extractGeography(cvData: any): string[] {
  const locations: string[] = [];

  // Från personuppgifter
  if (cvData.structuredCV?.personalInfo?.address) {
    locations.push(cvData.structuredCV.personalInfo.address);
  }

  // Från arbetserfarenheter
  if (cvData.structuredCV?.experience) {
    cvData.structuredCV.experience.forEach((exp: any) => {
      if (exp.location) {
        locations.push(exp.location);
      }
    });
  }

  return [...new Set(locations)];
}

/**
 * Extrahera kompetenser från CV
 */
export function extractSkills(cvData: any): string[] {
  const skills: string[] = [];

  if (cvData.structuredCV?.skills) {
    cvData.structuredCV.skills.forEach((skillItem: any) => {
      if (typeof skillItem === 'string') {
        skills.push(skillItem.toLowerCase());
      } else if (skillItem.skills) {
        skillItem.skills.forEach((skill: string) => {
          skills.push(skill.toLowerCase());
        });
      }
    });
  }

  return [...new Set(skills)];
}

/**
 * Extrahera utbildningar från CV
 */
export function extractEducations(cvData: any): Array<{
  degree: string;
  institution: string;
  year?: string;
}> {
  const educations: Array<{ degree: string; institution: string; year?: string }> = [];

  if (cvData.structuredCV?.education) {
    cvData.structuredCV.education.forEach((edu: any) => {
      educations.push({
        degree: edu.degree || '',
        institution: edu.institution || '',
        year: edu.graduationYear
      });
    });
  }

  return educations;
}

/**
 * Beräkna total arbetslivserfarenhet (år)
 */
export function calculateTotalExperience(cvData: any): number {
  if (!cvData.structuredCV?.experience) return 0;

  let totalYears = 0;

  for (const exp of cvData.structuredCV.experience) {
    try {
      const parseDate = (dateStr: string) => {
        const parts = dateStr.split('/');
        if (parts.length === 2) {
          const month = parseInt(parts[0]);
          const year = parseInt(parts[1]);
          return new Date(year, month - 1);
        }
        return null;
      };

      const startDate = parseDate(exp.startDate);
      const endDate = exp.endDate ? parseDate(exp.endDate) : new Date();

      if (startDate && endDate) {
        const years = (endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24 * 365.25);
        totalYears += years;
      }
    } catch {
      // Skip om datum inte kan parsas
    }
  }

  return totalYears;
}
